def test(src_emb, tgt_emb, pred_input, corr_data):
    se = KeyedVectors.load_word2vec_format(src_emb, binary=0,
                                           encoding='utf-8', unicode_errors='replace', limit=None)
    te = KeyedVectors.load_word2vec_format(tgt_emb, binary=0,
                                           encoding='utf-8', unicode_errors='replace', limit=None)
    sim_list = []
    for src_ind, tgt_ind in corr_data:
        sim = cosine_similarity(se.get_vector(src_ind).reshape(1, -1), te.get_vector(tgt_ind).reshape(1, -1))
        sim_list.append(sim[0][0])
    sim_list = np.array(sim_list)
    print("Cosine similarity: {}; {}".format(sim_list.mean(), ""))
    margin_list = []
    tmp_lst=[]
    with open(pred_input, 'r') as fin:
        for line in fin:
            data = line.split('\t')
            sid = data[0]
            tid = data[1]
            tmp_lst.append(float(data[2]))
            if (sid, tid) in corr_data:
                tsim = float(data[2])
                tsim_nearest = float(data[4])
                margin_list.append(tsim - tsim_nearest)
    mean_val = np.array(tmp_lst).mean()
    print("CSLS margin: {}".format(np.array(margin_list).mean()-mean_val))

